+struct MatchFunnelShiftAmountOpts {
+  Value *ShVal0 = nullptr;
+  Value *ShVal1 = nullptr;
+  Instruction *CtxI = nullptr;
+  /// If non-zero, use narrow/trunc-specific sub matching against WideWidth.
+  unsigned WideWidth = 0;
+  bool MatchConstants = false;
+};
